INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.8.140','cb','cb.adi.8','ЧБ Ади 8.140',140,'ঘর-দ্বার ভাঙ্গি’ শেষে বৃক্ষেরে দেখিয়া ।
তাহার উপরে ঠেঙ্গা পাড়ে দোহাতিয়া ॥১৪০॥','гхара-два̄ра бха̄н̇ги’ ш́еш̣е вр̣кш̣ере декхийа̄
та̄ха̄ра упаре т̣хен̇га̄ па̄д̣е доха̄тийа̄',NULL,NULL),('cb.adi.8.141','cb','cb.adi.8','ЧБ Ади 8.141',141,'তথাপিহ ক্রোধাবেশে ক্ষমা নাহি হয় ।
শেষে পৃথিবীতে ঠেঙ্গা নাহি সমুচ্চয় ॥১৪১॥','татха̄пиха кродха̄веш́е кш̣ама̄ на̄хи хайа
ш́еш̣е пр̣тхивӣте т̣хен̇га̄ на̄хи самуччайа',NULL,NULL),('cb.adi.8.142','cb','cb.adi.8','ЧБ Ади 8.142',142,'গৃহের উপান্তে শচী সশঙ্কিত হৈয়া ।
মহাভয়ে আছেন যেহেন লুকাইয়া ॥১৪২॥','гр̣хера упа̄нте ш́ачӣ саш́ан̇кита хаийа̄
маха̄бхайе а̄чхена йехена лука̄ийа̄',NULL,NULL),('cb.adi.8.143','cb','cb.adi.8','ЧБ Ади 8.143',143,'ধর্ম্মসংস্থাপক প্রভু ধর্ম্ম-সনাতন ।
জননীরে হস্ত নাহি তোলেন কখন ॥১৪৩॥','дхарма-сам̇стха̄пака прабху
дхарма-сана̄тана
джананӣре хаста на̄хи толена какхана',NULL,NULL),('cb.adi.8.144','cb','cb.adi.8','ЧБ Ади 8.144',144,'এতাদৃশ ক্রোধ আরো আছেন ব্যঞ্জিয়া ।
তথাপিহ জননীরে না মারিলা গিয়া ॥১৪৪॥','эта̄др̣ш́а кродха а̄ро а̄чхена вйан̃джийа̄
татха̄пиха джананӣре на̄ ма̄рила гийа̄',NULL,NULL),('cb.adi.8.145','cb','cb.adi.8','ЧБ Ади 8.145',145,'সকল ভাঙ্গিয়া শেষে আসিয়া অঙ্গনে ।
গড়াগড়ি যাইতে লাগিলা ক্রোধ-মনে ॥১৪৫॥','сакала бха̄н̇гийа̄ ш́еш̣е а̄сийа̄ ан̇гане
гад̣а̄гад̣и йа̄ите ла̄гила̄ кродха-мане',NULL,NULL),('cb.adi.8.146','cb','cb.adi.8','ЧБ Ади 8.146',146,'শ্রীকনক-অঙ্গ হৈলা বালুকা-বেষ্টিত ।
সেই হৈল মহাশোভা অকথ্য-চরিত ॥১৪৬॥','ш́рӣ-канака-ан̇га хаила̄ ба̄лука̄-веш̣т̣ита
сеи хаила маха̄ш́обха̄ акатхйа-чарита',NULL,NULL),('cb.adi.8.147','cb','cb.adi.8','ЧБ Ади 8.147',147,'কতক্ষণে মহাপ্রভু গড়াগড়ি দিয়া ।
স্থির হই’ রহিলেন শয়ন করিয়া ॥১৪৭॥','ката-кш̣ан̣е маха̄прабху гад̣а̄гад̣и дийа̄
стхира хаи’ рахилена ш́айана карийа̄',NULL,NULL),('cb.adi.8.148','cb','cb.adi.8','ЧБ Ади 8.148',148,'সেইমতে দৃষ্টি কৈলা যোগ-নিদ্রা প্রতি ।
পৃথিবীতে শুই’ আছে বৈকুণ্ঠের পতি ॥১৪৮॥','сеи-мате др̣ш̣т̣и каила̄ йога-нидра̄-прати
пр̣тхивӣте ш́уи’ а̄чхе ваикун̣т̣хера пати',NULL,NULL),('cb.adi.8.153','cb','cb.adi.8','ЧБ Ади 8.153',153,'এইমত মহাপ্রভু স্বানুভব-রসে ।
নিদ্রা যায় দেখি’ সর্ব্বদেবে কান্দে হাসে ॥১৫৩॥','эи-мата маха̄прабху сва̄нубхава-расе
нидра̄ йа̄йа декхи’ сарва-деве ка̄нде ха̄се',NULL,NULL),('cb.adi.8.154','cb','cb.adi.8','ЧБ Ади 8.154',154,'কতক্ষণে শচীদেবী মালা আনাইয়া ।
গঙ্গা পূজিবার সজ্জ প্রত্যক্ষ করিয়া ॥১৫৪॥','ката-кш̣ан̣е ш́ачӣдевӣ ма̄ла̄ а̄на̄ийа̄
ган̇га̄ пӯджибара саджджа пратйакш̣а карийа̄',NULL,NULL),('cb.adi.8.155','cb','cb.adi.8','ЧБ Ади 8.155',155,'ধীরে-ধীরে পুত্ত্রের শ্রীঅঙ্গে হস্ত দিয়া ।
ধূলা ঝাড়ি’ তুলিতে লাগিলা দেবী গিয়া ॥১৫৫॥','дхӣре дхӣре путрера ш́рӣ-ан̇ге хаста дийа̄
дхӯла̄ джха̄д̣и’ тулите ла̄гила̄ девӣ гийа̄',NULL,NULL),('cb.adi.8.156','cb','cb.adi.8','ЧБ Ади 8.156',156,'“উঠ উঠ, বাপ মোর, হের মালা ধর ।
আপন-ইচ্ছায় গিয়া গঙ্গা পূজা কর ॥১৫৬॥','‘ут̣ха ут̣ха, ба̄па мора, хера ма̄ла̄ дхара
а̄пана-иччха̄йа гийа̄ ган̇га̄ пӯджа̄ кара',NULL,NULL),('cb.adi.8.157','cb','cb.adi.8','ЧБ Ади 8.157',157,'ভাল হৈল, বাপ, যত ফেলিলা ভাঙ্গিয়া ।
যাউক তোমার সব বালাই লইয়া” ॥১৫৭॥','бха̄ла хаила, ба̄па, йата пхелила̄ бха̄н̇гийа̄
йа̄ука тома̄ра саба ба̄ла̄и лаийа̄’',NULL,NULL),('cb.adi.8.158','cb','cb.adi.8','ЧБ Ади 8.158',158,'জননীর বাক্য শুনি’ শ্রীগৌরসুন্দর ।
চলিলা করিতে স্নান লজ্জিত-অন্তর ॥১৫৮॥','джананӣра ва̄кйа ш́уни’ ш́рӣ-гаурасундара
чалила̄ карите сна̄на ладжджита-антара',NULL,NULL),('cb.adi.8.159','cb','cb.adi.8','ЧБ Ади 8.159',159,'এথা শচী সর্ব্বগৃহ করি’ উপস্কার ।
রন্ধনের উযোগ লাগিলা করিবার ॥১৫৯॥','этха̄ ш́ачӣ сарва-гр̣ха кари’ упаска̄ра
рандханера удйога ла̄гила̄ кариба̄ра',NULL,NULL),('cb.adi.8.160','cb','cb.adi.8','ЧБ Ади 8.160',160,'যদ্যপিহ প্রভু এত করে অপচয় ।
তথাপি শচীর চিত্তে দুঃখ নাহি হয় ॥১৬০॥','татха̄пи ш́ачӣра читте дух̣кха на̄хи хайа',NULL,NULL),('cb.adi.8.161','cb','cb.adi.8','ЧБ Ади 8.161',161,'কৃষ্ণের চাপল্য যেন অশেষ-প্রকারে ।
মা যশোদা সহিলেন গোকুল-নগরে ॥১৬১॥','кр̣ш̣н̣ера ча̄палйа йена аш́еш̣а-прака̄ре
йаш́ода̄ сахилена гокула-нагаре',NULL,NULL),('cb.adi.8.162','cb','cb.adi.8','ЧБ Ади 8.162',162,'এইমত গৌরাঙ্গের যত চঞ্চলতা ।
সহিলেন অনুক্ষণ শচী জগন্মাতা ॥১৬২॥','эи-мата гаура̄н̇гера йата чан̃чалата̄
сахилена анукш̣ан̣а ш́ачӣ джаган-ма̄та̄',NULL,NULL),('cb.adi.8.163','cb','cb.adi.8','ЧБ Ади 8.163',163,'ঈশ্বরের ক্রীড়া জানি কহিতে কতেক ।
এইমত চঞ্চলতা করেন যতেক ॥১৬৩॥','ӣш́варера крӣд̣а̄ джа̄ни кахите катека
эи-мата чан̃чалата̄ карена йатека',NULL,NULL),('cb.adi.8.164','cb','cb.adi.8','ЧБ Ади 8.164',164,'সকল সহেন আই কায়-বাক্য-মনে ।
হইলেন শচী যেন পৃথিবী আপনে ॥১৬৪॥','сакала сахена а̄и ка̄йа-ва̄кйа-мане
хаилена ш́ачӣ йена пр̣тхивӣ а̄пане',NULL,NULL),('cb.adi.8.165','cb','cb.adi.8','ЧБ Ади 8.165',165,'কতক্ষণে মহাপ্রভু করি’ গঙ্গাস্নান ।
আইলেন গৃহে ক্রীড়াময় ভগবান্ ॥১৬৫॥','ката-кш̣ан̣е маха̄прабху кари’ ган̇га̄-сна̄на
а̄илена гр̣хе крӣд̣а̄-майа бхагава̄н',NULL,NULL),('cb.adi.8.166','cb','cb.adi.8','ЧБ Ади 8.166',166,'বিষ্ণুপূজা করি’ তুলসীরে জল দিয়া ।
ভোজন করিতে প্রভু বসিলেন গিয়া ॥১৬৬॥','виш̣н̣у-пӯджа̄ кари’ туласӣре джала дийа̄
бходжана карите прабху василена гийа̄',NULL,NULL),('cb.adi.8.167','cb','cb.adi.8','ЧБ Ади 8.167',167,'ভোজন করিয়া প্রভু হৈলা হর্ষ-মন ।
আচমন করি’ করেন তাম্বূল-চর্ব্বণ ॥১৬৭॥','бходжана карийа̄ прабху хаила̄ харш̣а-мана
а̄чамана кари’ карена та̄мбӯла-чарван̣а',NULL,NULL),('cb.adi.8.168','cb','cb.adi.8','ЧБ Ади 8.168',168,'ধীরে-ধীরে আই তবে বলিতে লাগিলা ।
“এত অপচয়, বাপ, কি কার্য্যে করিলা? ॥১৬৮॥','дхӣре дхӣре а̄и табе балите ла̄гила̄
‘ета апачайа, ба̄па, ки-ка̄рйе карила̄?',NULL,NULL),('cb.adi.8.169','cb','cb.adi.8','ЧБ Ади 8.169',169,'ঘর-দ্বার দ্রব্য যত, সকলি তোমার ।
অপচয় তোমার সে, কি দায় আমার? ॥১৬৯॥','гхара два̄ра дравйа йата, сакали тома̄ра
апачайа тома̄ра се, ки да̄йа а̄ма̄ра?',NULL,NULL),('cb.adi.8.170','cb','cb.adi.8','ЧБ Ади 8.170',170,'পড়িবারে তুমি বোল এখনি যাইবা ।
ঘরেতে সম্বল নাহি,—কালি কি খাইবা?” ॥১৭০॥','пад̣иба̄ре туми бола экхани йа̄иба̄
гхарете самбала на̄хи, — ка̄ли ки кха̄иба̄?’',NULL,NULL),('cb.adi.8.171','cb','cb.adi.8','ЧБ Ади 8.171',171,'হাসে প্রভু জননীর শুনিয়া বচন ।
প্রভু বোলে,—“কৃষ্ণ পোষ্টা, করিবে পোষণ” ॥১৭১॥','ха̄се прабху джананӣра ш́унийа̄ вачана
прабху боле, — ‘кр̣ш̣н̣а пош̣т̣а̄, карибе пош̣ан̣а’',NULL,NULL),('cb.adi.8.172','cb','cb.adi.8','ЧБ Ади 8.172',172,'এত বলি’ পুস্তক লইয়া প্রভু করে ।
সরস্বতীপতি চলিলেন পড়িবারে ॥১৭২॥','эта бали’ пустака лаийа̄ прабху каре
сарасватӣ-пати чалилена пад̣иба̄ре',NULL,NULL),('cb.adi.8.173','cb','cb.adi.8','ЧБ Ади 8.173',173,'কতক্ষণ বিদ্যা-রস করি’ কুতূহলে ।
জাহ্নবীর কূলে আইলেন সন্ধ্যাকালে ॥১৭৩॥','ката-кш̣ан̣а видйа̄-раса кари кутӯхале
джа̄хнавӣра кӯле а̄илена сандхйа̄-ка̄ле',NULL,NULL),('cb.adi.8.174','cb','cb.adi.8','ЧБ Ади 8.174',174,'কতক্ষণ থাকি’ প্রভু জাহ্নবীর তীরে ।
তবে পুনঃ আইলেন আপন-মন্দিরে ॥১৭৪॥','ката-кш̣ан̣а тха̄ки’ прабху джа̄хнавӣра тӣре
табе пунах̣ а̄илена а̄пана-мандире',NULL,NULL),('cb.adi.8.175','cb','cb.adi.8','ЧБ Ади 8.175',175,'জননীরে ডাক দিয়া আনিঞা নিভৃতে ।
দিব্য স্বর্ণ তোলা দুই দিলা তান হাতে ॥১৭৫॥','джананӣре д̣а̄ка дийа̄ а̄нин̃а̄ нибхр̣те
дивйа сварн̣а тола̄ дуи дила̄ дила̄ та̄’на ха̄те',NULL,NULL),('cb.adi.8.176','cb','cb.adi.8','ЧБ Ади 8.176',176,'“দেখ, মাতা, কৃষ্ণ এই দিলেন সম্বল ।
ইহা ভাঙ্গাইয়া ব্যয় করহ সকল” ॥১৭৬॥','‘декха, ма̄та̄, кр̣ш̣н̣а эи дилена самбала
иха̄ бха̄н̇га̄ийа̄ вйайа караха сакала’',NULL,NULL),('cb.adi.8.177','cb','cb.adi.8','ЧБ Ади 8.177',177,'এত বলি’ মহাপ্রভু চলিলা শয়নে ।
পরম-বিস্মিত হই’ আই মনে গণে’ ॥১৭৭॥','эта бали’ маха̄прабху чалила̄ ш́айане
парама-висмита хаи’ а̄и мане ган̣е’',NULL,NULL),('cb.adi.8.178','cb','cb.adi.8','ЧБ Ади 8.178',178,'“কোথা হইতে সুবর্ণ আনয়ে বারেবার ।
পাছে কোন প্রমাদ জন্মায় আসি’ আর ॥১৭৮॥','‘котха̄ хаите суварн̣а а̄найе ба̄реба̄ра
па̄чхе кона прама̄да джанма̄йа а̄си’ а̄ра',NULL,NULL),('cb.adi.8.179','cb','cb.adi.8','ЧБ Ади 8.179',179,'যেই-মাত্র সম্বল সঙ্কোচ হয় ঘরে ।
সেই এইমত সোণা আনে বারেবারে ॥১৭৯॥','йеи-ма̄тра самбала-сан̇коча хайа гхаре
сеи эи-мата сон̣а̄ а̄не ба̄ре-ба̄ре',NULL,NULL),('cb.adi.8.180','cb','cb.adi.8','ЧБ Ади 8.180',180,'কিবা ধার করে, কিবা কোন সিদ্ধি জানে? ।
কোন্রূপে কার সোণা আনে বা কেমনে?” ॥১৮০॥','киба̄ дха̄ра каре, киба̄ кон сиддхи йане?
кон рӯпе ка’ра сона ане ва̄ кемане?’',NULL,NULL),('cb.adi.8.181','cb','cb.adi.8','ЧБ Ади 8.181',181,'মহা-অকৈতব আই পরম উদার ।
ভাঙ্গাইতে দিতেও ডরায় বারেবার ॥১৮১॥','маха̄-акаитава а̄и парама-уда̄ра
бха̄н̇га̄ите дитео д̣ара̄йа ба̄ре-ба̄ра',NULL,NULL),('cb.adi.8.182','cb','cb.adi.8','ЧБ Ади 8.182',182,'“দশঠাঞি পাঁচঠাঞি দেখাইয়া আগে” ।
লোকেরে শিখায় আই, “ভাঙ্গাইবি তবে” ॥১৮২॥','‘даш́а-т̣ха̄н̃и па̄н̃ча-т̣ха̄н̃и декха̄ийа̄ а̄ге’
локере ш́икха̄йа а̄и ‘бха̄н̇га̄иби табе’',NULL,NULL),('cb.adi.8.183','cb','cb.adi.8','ЧБ Ади 8.183',183,'হেনমতে মহাপ্রভু সর্ব্ব-সিদ্ধীশ্বর ।
গুপ্তভাবে আছে নবদ্বীপের ভিতর ॥১৮৩॥','хена мате маха̄прабху сарва-сиддхӣш́вара
